// ============================================================
// STEP 1: Pehle SIRF YAHI file paste karo aur dekho kya dikhta hai
// Agar yeh kaam kare toh original code ka issue hai
// ============================================================

import React, { useState, useEffect } from "react";

// ── Safe imports — crash nahi karega ────────────────────────
let Nav = () => null; // Default: kuch nahi render karega
try {
  Nav = require("./Nev").default;
} catch (e) {
  console.warn("Nav component load nahi hua:", e.message);
}

let useNavigate = () => () => {};
try {
  useNavigate = require("react-router-dom").useNavigate;
} catch (e) {
  console.warn("react-router-dom nahi mila");
}

// ── Demo Data ────────────────────────────────────────────────
const DEMO_PETS = [
  { id:"1", pname:"Affenpinscher",    price:10000, cat:"Dogs",    age:"8 weeks",  rating:4.8, reviews:124, badge:{label:"POPULAR",cls:"badge-popular"} },
  { id:"2", pname:"Alaskan",          price:20000, cat:"Dogs",    age:"10 weeks", rating:4.6, reviews:89,  badge:{label:"NEW",cls:"badge-new"} },
  { id:"3", pname:"Alaskan Malamute", price:10000, cat:"Dogs",    age:"3 months", rating:4.9, reviews:203, badge:{label:"PREMIUM",cls:"badge-premium"} },
  { id:"4", pname:"Airedale Terrier", price:400000,cat:"Dogs",    age:"2 months", rating:4.7, reviews:156, badge:{label:"VERIFIED",cls:"badge-verified"} },
  { id:"5", pname:"Dog Breeds",       price:23333, cat:"Dogs",    age:"12 weeks", rating:4.5, reviews:67,  badge:{label:"POPULAR",cls:"badge-popular"} },
  { id:"6", pname:"Persian Cat",      price:15000, cat:"Cats",    age:"8 weeks",  rating:4.8, reviews:178, badge:{label:"NEW",cls:"badge-new"} },
  { id:"7", pname:"Labrador",         price:18000, cat:"Dogs",    age:"10 weeks", rating:4.9, reviews:312, badge:{label:"PREMIUM",cls:"badge-premium"} },
  { id:"8", pname:"Golden Retriever", price:22000, cat:"Dogs",    age:"3 months", rating:4.8, reviews:189, badge:{label:"VERIFIED",cls:"badge-verified"} },
];

const FALLBACK_IMGS = [
  "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=500&q=80",
  "https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=500&q=80",
  "https://images.unsplash.com/photo-1537151608828-ea2b11777ee8?w=500&q=80",
  "https://images.unsplash.com/photo-1583511655857-d19b40a7a54e?w=500&q=80",
  "https://images.unsplash.com/photo-1601979031925-424e53b6caaa?w=500&q=80",
  "https://images.unsplash.com/photo-1518717758536-85ae29035b6d?w=500&q=80",
  "https://images.unsplash.com/photo-1587300003388-59208cc962cb?w=500&q=80",
  "https://images.unsplash.com/photo-1548199973-03cce0bbc87b?w=500&q=80",
];

const CATEGORIES = ["All","Dogs","Cats","Birds","Fish","Rabbits","Exotic"];
const CAT_ICONS  = { All:"🐾",Dogs:"🐕",Cats:"🐈",Birds:"🦜",Fish:"🐠",Rabbits:"🐇",Exotic:"🦎" };

const starsStr = (r) => {
  const f = Math.floor(r||0);
  return "★".repeat(f) + "☆".repeat(Math.max(0, 5-f));
};

const css = `
@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,700;1,700&family=Outfit:wght@300;400;500;600;700&display=swap');

:root{
  --bg:#f4f1eb; --bg2:#ede8de; --surface:#fff;
  --sage:#3d6b4f; --sage-d:#2a4e39; --sage-l:#5a9470;
  --sage-xs:rgba(61,107,79,.09);
  --gold:#b8922a; --gold-l:#d4ac48; --gold-xs:rgba(184,146,42,.12);
  --border:rgba(61,107,79,.13); --border2:rgba(184,146,42,.18);
  --text:#1c2b22; --text2:#3a4a3f; --muted:#7a907f; --dim:#aab8ac;
  --ivory:#fdf9f2;
  --shadow:0 4px 24px rgba(30,50,35,.08);
  --shadow-lg:0 16px 60px rgba(30,50,35,.14);
  --radius:20px;
}
*{box-sizing:border-box;margin:0;padding:0;}
::-webkit-scrollbar{width:5px;}
::-webkit-scrollbar-thumb{background:var(--sage);border-radius:10px;}

.pg{min-height:100vh;background:var(--bg);font-family:'Outfit',sans-serif;color:var(--text);}

/* HERO */
.hero{background:linear-gradient(160deg,#1e3a28,#2a5a3c,#1a4030);padding:80px 24px 96px;text-align:center;position:relative;overflow:hidden;}
.hero-orb{position:absolute;border-radius:50%;filter:blur(80px);opacity:.18;pointer-events:none;animation:orbDrift 14s ease-in-out infinite;}
.hero-orb1{width:400px;height:400px;background:var(--sage-l);top:-100px;left:-100px;}
.hero-orb2{width:300px;height:300px;background:var(--gold-l);bottom:-50px;right:-50px;animation-delay:-7s;}
.hero-wave{position:absolute;bottom:0;left:0;right:0;height:64px;background:var(--bg);clip-path:ellipse(58% 100% at 50% 100%);}
.hero-inner{position:relative;z-index:2;max-width:760px;margin:0 auto;}
.hero-pill{display:inline-flex;align-items:center;gap:8px;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.2);color:rgba(255,255,255,.85);font-size:.72rem;font-weight:600;letter-spacing:.2em;text-transform:uppercase;padding:7px 20px;border-radius:50px;margin-bottom:22px;}
.hero-inner h1{font-family:'Cormorant Garamond',serif;font-size:clamp(36px,6vw,68px);font-weight:700;line-height:1.08;color:#fff;margin-bottom:16px;}
.hero-inner h1 em{font-style:italic;color:#a8d4b8;}
.hero-inner p{color:rgba(255,255,255,.52);font-size:1rem;font-weight:300;max-width:480px;margin:0 auto 36px;line-height:1.75;}
.hero-stats{display:flex;justify-content:center;gap:48px;flex-wrap:wrap;}
.stat-num{font-family:'Cormorant Garamond',serif;font-size:2rem;font-weight:700;color:#a8d4b8;display:block;}
.stat-lbl{font-size:.68rem;color:rgba(255,255,255,.4);letter-spacing:.18em;text-transform:uppercase;}

/* BAR */
.bar{max-width:1100px;margin:-26px auto 0;padding:0 20px;position:relative;z-index:10;}
.bar-inner{background:var(--surface);border-radius:var(--radius);padding:18px 22px;box-shadow:0 12px 48px rgba(30,50,35,.12);border:1px solid var(--border);display:flex;gap:12px;align-items:center;flex-wrap:wrap;}
.search-box{flex:1;min-width:180px;display:flex;align-items:center;gap:10px;background:var(--bg);border:1.5px solid var(--border);border-radius:50px;padding:10px 18px;transition:.2s;}
.search-box:focus-within{border-color:var(--sage);box-shadow:0 0 0 3px rgba(61,107,79,.1);}
.search-box input{border:none;background:transparent;outline:none;font-family:'Outfit',sans-serif;font-size:.875rem;color:var(--text);width:100%;}
.search-box input::placeholder{color:var(--dim);}
.sort-sel{background:var(--bg);border:1.5px solid var(--border);border-radius:50px;padding:10px 14px;font-family:'Outfit',sans-serif;font-size:.85rem;font-weight:500;color:var(--text);cursor:pointer;outline:none;}
.sort-sel:focus{border-color:var(--sage);}
.view-btns{display:flex;gap:6px;}
.vbtn{width:38px;height:38px;border-radius:50%;border:1.5px solid var(--border);background:transparent;cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center;transition:.2s;color:var(--muted);}
.vbtn:hover,.vbtn.on{background:var(--sage-xs);border-color:var(--sage);color:var(--sage);}

/* CATS */
.cats{max-width:1100px;margin:18px auto 0;padding:0 20px;display:flex;gap:8px;flex-wrap:wrap;}
.cat{padding:8px 18px;border-radius:50px;border:1.5px solid var(--border);background:var(--surface);color:var(--muted);font-family:'Outfit',sans-serif;font-size:.8rem;font-weight:500;cursor:pointer;transition:.2s;display:flex;align-items:center;gap:6px;}
.cat:hover{border-color:var(--sage);color:var(--sage);}
.cat.on{background:var(--sage);border-color:var(--sage);color:#fff;box-shadow:0 4px 16px rgba(61,107,79,.3);}
.cat-cnt{font-size:.68rem;padding:1px 7px;border-radius:50px;background:rgba(0,0,0,.08);}
.cat.on .cat-cnt{background:rgba(255,255,255,.25);}

/* INFO */
.info-row{max-width:1100px;margin:18px auto 0;padding:0 20px;display:flex;justify-content:space-between;align-items:center;}
.info-txt{font-size:.82rem;color:var(--muted);}
.info-txt strong{color:var(--text);font-weight:600;}
.clear-btn{font-size:.78rem;color:var(--sage);cursor:pointer;font-weight:600;background:none;border:none;font-family:'Outfit',sans-serif;}

/* GRID */
.grid{max-width:1100px;margin:20px auto 0;padding:0 20px 100px;display:grid;gap:22px;grid-template-columns:repeat(auto-fill,minmax(250px,1fr));}
.grid.lv{grid-template-columns:1fr;}

/* CARD */
.card{background:var(--surface);border-radius:var(--radius);border:1px solid var(--border);overflow:hidden;cursor:pointer;position:relative;box-shadow:var(--shadow);transition:transform .4s cubic-bezier(.34,1.56,.64,1),box-shadow .4s ease,border-color .3s ease;animation:fadeUp .4s ease both;}
.card:hover{transform:translateY(-10px);box-shadow:0 20px 60px rgba(30,50,35,.16);border-color:rgba(61,107,79,.3);}
.card.lv{display:grid;grid-template-columns:230px 1fr;}
.card.lv:hover{transform:translateY(-5px);}

.img-wrap{position:relative;overflow:hidden;aspect-ratio:4/3;background:var(--bg2);}
.card.lv .img-wrap{aspect-ratio:unset;min-height:190px;}
.card-img{width:100%;height:100%;object-fit:cover;transition:transform .55s ease;}
.card:hover .card-img{transform:scale(1.07);}

.badge{position:absolute;top:12px;left:12px;padding:4px 11px;border-radius:50px;font-size:.65rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase;color:#fff;}
.badge-popular{background:var(--sage);}
.badge-new{background:#3ecf8e;}
.badge-premium{background:#7c5cfc;}
.badge-verified{background:var(--gold);}

.wish{position:absolute;top:12px;right:12px;width:34px;height:34px;border-radius:50%;background:rgba(255,255,255,.92);border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:16px;transition:.25s;opacity:0;transform:scale(.7);}
.card:hover .wish{opacity:1;transform:scale(1);}
.wish.on{opacity:1;transform:scale(1);}
.wish:hover{transform:scale(1.18)!important;}

.qv{position:absolute;bottom:12px;left:50%;transform:translateX(-50%) translateY(10px);background:rgba(255,255,255,.96);border:none;border-radius:50px;padding:7px 18px;font-family:'Outfit',sans-serif;font-size:.75rem;font-weight:600;color:var(--sage-d);cursor:pointer;white-space:nowrap;opacity:0;transition:.25s;}
.card:hover .qv{opacity:1;transform:translateX(-50%) translateY(0);}

.body{padding:18px;}
.card.lv .body{padding:22px 26px;display:flex;flex-direction:column;justify-content:center;}
.cat-tag{font-size:.68rem;font-weight:700;letter-spacing:.18em;text-transform:uppercase;color:var(--sage);margin-bottom:6px;display:flex;align-items:center;gap:5px;}
.cat-tag::before{content:'';display:inline-block;width:5px;height:5px;border-radius:50%;background:var(--sage-l);}
.pname{font-family:'Cormorant Garamond',serif;font-size:1.25rem;font-weight:700;color:var(--text);margin:0 0 3px;line-height:1.25;}
.card.lv .pname{font-size:1.55rem;}
.age{font-size:.75rem;color:var(--muted);margin-bottom:6px;}
.desc{font-size:.8rem;color:var(--muted);line-height:1.65;margin-bottom:10px;display:none;}
.card.lv .desc{display:block;}
.rat{display:flex;align-items:center;gap:5px;margin-bottom:13px;}
.stars{color:var(--gold);font-size:.75rem;letter-spacing:1px;}
.revs{font-size:.7rem;color:var(--dim);}
.price-row{display:flex;align-items:center;justify-content:space-between;gap:8px;}
.price{font-family:'Cormorant Garamond',serif;font-size:1.55rem;font-weight:700;color:var(--sage-d);line-height:1;}
.price sup{font-size:.85rem;font-family:'Outfit',sans-serif;font-weight:500;color:var(--muted);}
.btns{display:flex;gap:7px;align-items:center;}
.cart-btn{padding:8px 14px;border-radius:50px;border:none;background:var(--sage-l);color:#fff;font-family:'Outfit',sans-serif;font-size:.75rem;font-weight:600;cursor:pointer;transition:.22s;white-space:nowrap;display:flex;align-items:center;gap:5px;box-shadow:0 4px 12px rgba(61,107,79,.25);}
.cart-btn:hover{background:var(--sage-d);}
.cart-btn.ok{background:#1D9E75;}
.wa-btn{width:34px;height:34px;border-radius:50%;border:1.5px solid var(--border2);background:var(--gold-xs);cursor:pointer;font-size:14px;transition:.2s;display:flex;align-items:center;justify-content:center;flex-shrink:0;}
.wa-btn:hover{border-color:var(--gold);transform:scale(1.1);}

/* MODAL */
.modal-bg{position:fixed;inset:0;background:rgba(10,22,14,.75);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px;backdrop-filter:blur(8px);}
.modal{background:var(--ivory);border-radius:var(--radius);max-width:680px;width:100%;max-height:90vh;overflow-y:auto;position:relative;box-shadow:var(--shadow-lg);border:1px solid var(--border);}
.modal-img{width:100%;height:280px;object-fit:cover;border-radius:var(--radius) var(--radius) 0 0;}
.modal-close{position:absolute;top:14px;right:14px;width:36px;height:36px;border-radius:50%;background:rgba(255,255,255,.95);border:none;font-size:16px;cursor:pointer;display:flex;align-items:center;justify-content:center;transition:.22s;}
.modal-close:hover{transform:rotate(90deg);}
.modal-body{padding:24px 28px 30px;}
.modal-name{font-family:'Cormorant Garamond',serif;font-size:1.9rem;font-weight:700;color:var(--text);margin:0 0 8px;}
.modal-price{font-family:'Cormorant Garamond',serif;font-size:2rem;font-weight:700;color:var(--sage-d);margin:0 0 16px;}
.modal-feats{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:20px;}
.feat{background:var(--bg);border:1px solid var(--border);border-radius:14px;padding:11px 13px;font-size:.8rem;color:var(--muted);}
.feat strong{display:block;font-size:.85rem;font-weight:600;color:var(--text2);margin-bottom:2px;}
.modal-acts{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:10px;}
.modal-cart{flex:1;min-width:130px;padding:12px 18px;background:var(--sage-l);color:#fff;border:none;border-radius:50px;font-family:'Outfit',sans-serif;font-size:.875rem;font-weight:600;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:8px;box-shadow:0 6px 20px rgba(61,107,79,.3);transition:.22s;}
.modal-cart:hover{background:var(--sage-d);}
.modal-wa{padding:12px 20px;border-radius:50px;border:1.5px solid var(--border2);background:var(--gold-xs);font-family:'Outfit',sans-serif;font-size:.875rem;font-weight:600;color:var(--gold);cursor:pointer;display:flex;align-items:center;gap:7px;transition:.22s;}
.modal-wa:hover{background:var(--gold);color:#fff;}
.modal-wl{padding:12px 14px;border-radius:50px;border:1.5px solid var(--border);background:transparent;font-size:18px;cursor:pointer;}
.buy-now{width:100%;padding:13px;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:#fff;border:none;border-radius:50px;font-family:'Outfit',sans-serif;font-size:.9rem;font-weight:700;cursor:pointer;transition:.22s;display:flex;align-items:center;justify-content:center;gap:8px;box-shadow:0 6px 20px rgba(184,146,42,.3);}
.buy-now:hover{opacity:.88;}

/* SKEL */
.skel{background:var(--surface);border-radius:var(--radius);overflow:hidden;border:1px solid var(--border);}
.skel-img{height:190px;background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);background-size:200%;animation:shimmer 1.5s ease infinite;}
.skel-body{padding:18px;}
.skel-line{height:11px;border-radius:6px;margin-bottom:10px;background:linear-gradient(90deg,var(--bg2) 25%,var(--bg) 50%,var(--bg2) 75%);background-size:200%;animation:shimmer 1.5s ease infinite;}
.skel-line.w70{width:70%;}.skel-line.w50{width:50%;}

/* EMPTY */
.empty{grid-column:1/-1;text-align:center;padding:80px 20px;}
.empty-icon{font-size:60px;display:block;margin-bottom:16px;}
.empty h3{font-family:'Cormorant Garamond',serif;font-size:1.5rem;font-weight:700;color:var(--text);margin:0 0 8px;}
.empty p{font-size:.875rem;color:var(--muted);}

/* TOAST */
.toast{position:fixed;bottom:26px;right:26px;z-index:99999;background:var(--sage-d);color:#fff;border-radius:50px;padding:13px 22px;font-size:.875rem;font-weight:500;box-shadow:0 8px 32px rgba(0,0,0,.2);display:flex;align-items:center;gap:10px;transform:translateY(80px);opacity:0;transition:all .35s cubic-bezier(.34,1.46,.64,1);}
.toast.on{transform:translateY(0);opacity:1;}

/* KEYFRAMES */
@keyframes fadeUp{from{opacity:0;transform:translateY(28px)}to{opacity:1;transform:none}}
@keyframes orbDrift{0%,100%{transform:translate(0,0) scale(1)}40%{transform:translate(40px,-30px) scale(1.08)}70%{transform:translate(-20px,20px) scale(.96)}}
@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}

/* RESPONSIVE */
@media(max-width:1100px){.grid{grid-template-columns:repeat(auto-fill,minmax(220px,1fr));}}
@media(max-width:680px){
  .hero{padding:56px 16px 72px;}
  .hero-stats{gap:24px;}
  .grid{grid-template-columns:repeat(auto-fill,minmax(155px,1fr));gap:14px;}
  .card.lv{grid-template-columns:1fr;}
  .modal-feats{grid-template-columns:1fr;}
  .modal-body{padding:18px 16px 24px;}
}
`;

const WHATSAPP = "919999999999";
const API = "http://localhost/Petshop/show.php";

export default function PetGallery() {
  let navigate;
  try { navigate = useNavigate(); } catch(e) { navigate = (p) => { window.location.href = p; }; }

  const [pets, setPets]       = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch]   = useState("");
  const [cat, setCat]         = useState("All");
  const [sort, setSort]       = useState("default");
  const [view, setView]       = useState("grid");
  const [wl, setWl]           = useState([]);
  const [added, setAdded]     = useState({});
  const [modal, setModal]     = useState(null);
  const [toast, setToast]     = useState({ on:false, msg:"" });

  useEffect(() => {
    let done = false;

    // Guaranteed fallback after 4s
    const t = setTimeout(() => {
      if (!done) { done=true; load(DEMO_PETS); }
    }, 4000);

    fetch(API)
      .then(r => { if(!r.ok) throw 0; return r.json(); })
      .then(data => {
        if (done) return;
        done = true; clearTimeout(t);
        const arr = Array.isArray(data) ? data.filter(p=>p&&p.pname) : [];
        load(arr.length ? arr : DEMO_PETS);
      })
      .catch(() => {
        if (done) return;
        done = true; clearTimeout(t);
        load(DEMO_PETS);
      });

    function load(src) {
      setPets(src.map((p,i) => ({
        ...p,
        id:      p.id || String(i+1),
        pname:   p.pname || "Unknown",
        price:   parseInt(p.price)||0,
        cat:     p.cat  || (CAT_MAP[p.pname] || "Dogs"),
        desc:    p.desc || (DESC_MAP[p.pname] || "A healthy, vaccinated companion."),
        age:     p.age  || AGES[i % AGES.length],
        rating:  p.rating  || getRating(i+1),
        reviews: p.reviews || getReviews(i+1),
        badge:   p.badge   || BADGE_DATA[(i) % BADGE_DATA.length],
        img:     (p.image && p.image.trim()) ? p.image : FALLBACK_IMGS[i % FALLBACK_IMGS.length],
      })));
      setLoading(false);
    }

    return () => clearTimeout(t);
  }, []);

  const CAT_MAP  = { Affenpinscher:"Dogs",Alaskan:"Dogs","Alaskan Malamute":"Dogs","Airedale Terrier":"Dogs","Dog Breeds":"Dogs",Husky:"Dogs",Labrador:"Dogs","Golden Retriever":"Dogs","Persian Cat":"Cats","Maine Coon":"Cats",Siamese:"Cats","Indian Ringneck":"Birds",Parrot:"Birds",Arowana:"Fish",Goldfish:"Fish","Lop-eared Rabbit":"Rabbits",Rabbit:"Rabbits","Bearded Dragon":"Exotic" };
  const DESC_MAP = { Affenpinscher:"Playful, curious & fearless. The perfect apartment companion.",Alaskan:"Energetic sled breed that thrives on outdoor adventures.","Alaskan Malamute":"Powerful & loyal. Built for active families.","Airedale Terrier":"King of terriers — intelligent & confident.","Dog Breeds":"Premium mixed-breed companion.","Persian Cat":"Silky fur, calm & loving. Perfect indoor companion.",Labrador:"Energetic, obedient & affectionate.",  "Golden Retriever":"Friendly, loyal & great with kids." };
  const BADGE_DATA = [{label:"POPULAR",cls:"badge-popular"},{label:"NEW",cls:"badge-new"},{label:"PREMIUM",cls:"badge-premium"},{label:"VERIFIED",cls:"badge-verified"}];
  const AGES = ["8 weeks","10 weeks","3 months","2 months","12 weeks","6 months"];
  const getRating  = (id) => +(4.5 + ((id*7)%5)/10).toFixed(1);
  const getReviews = (id) => 40 + ((id*37)%200);

  const showToast = (msg) => {
    setToast({on:true,msg});
    setTimeout(()=>setToast({on:false,msg:""}),3000);
  };

  const toggleWl = (id, e) => {
    e?.stopPropagation();
    setWl(w => w.includes(id) ? w.filter(x=>x!==id) : [...w,id]);
  };

  const addCart = (pet, e) => {
    e?.stopPropagation();
    try { localStorage.setItem("item",pet.price); localStorage.setItem("pid",pet.id); } catch(_){}
    setAdded(a=>({...a,[pet.id]:true}));
    setTimeout(()=>setAdded(a=>({...a,[pet.id]:false})),1600);
    showToast("🛒 "+pet.pname+" added to cart!");
  };

  const buyNow = (pet) => { addCart(pet); setTimeout(()=>navigate("/checkout"),350); };

  const waInquiry = (pet, e) => {
    e?.stopPropagation();
    window.open("https://wa.me/"+WHATSAPP+"?text="+encodeURIComponent("Hi! I'm interested in *"+pet.pname+"* listed at ₹"+pet.price.toLocaleString("en-IN")+". Please share details."),"_blank");
  };

  const filtered = pets
    .filter(p => cat==="All" || p.cat===cat)
    .filter(p => p.pname.toLowerCase().includes(search.toLowerCase()))
    .sort((a,b) => {
      if(sort==="price-asc") return a.price-b.price;
      if(sort==="price-desc") return b.price-a.price;
      if(sort==="rating") return b.rating-a.rating;
      if(sort==="name") return a.pname.localeCompare(b.pname);
      return 0;
    });

  const catCnt = (c) => c==="All" ? pets.length : pets.filter(p=>p.cat===c).length;

  return (
    <>
      <style dangerouslySetInnerHTML={{__html:css}} />
      <div className="pg">

        <Nav />

        {/* HERO */}
        <div className="hero">
          <div className="hero-orb hero-orb1"/>
          <div className="hero-orb hero-orb2"/>
          <div className="hero-inner">
            <div className="hero-pill">🐾 Premium Pet Marketplace</div>
            <h1>Find Your Perfect<br/><em>Companion</em></h1>
            <p>Hand-picked, vaccinated & health-certified pets from trusted breeders across India.</p>
            <div className="hero-stats">
              {[
                {num:pets.length?pets.length+"+":"50+",lbl:"Pets Available"},
                {num:"100%",lbl:"Health Verified"},
                {num:"4.9★",lbl:"Avg Rating"},
                {num:"Free",lbl:"Home Delivery"},
              ].map((s,i)=>(
                <div key={i}>
                  <span className="stat-num">{s.num}</span>
                  <span className="stat-lbl">{s.lbl}</span>
                </div>
              ))}
            </div>
          </div>
          <div className="hero-wave"/>
        </div>

        {/* SEARCH BAR */}
        <div className="bar">
          <div className="bar-inner">
            <div className="search-box">
              <span>🔍</span>
              <input placeholder="Search breed..." value={search} onChange={e=>setSearch(e.target.value)}/>
            </div>
            <select className="sort-sel" value={sort} onChange={e=>setSort(e.target.value)}>
              <option value="default">Featured</option>
              <option value="price-asc">Price: Low → High</option>
              <option value="price-desc">Price: High → Low</option>
              <option value="rating">Top Rated</option>
              <option value="name">A → Z</option>
            </select>
            <div className="view-btns">
              <button className={"vbtn"+(view==="grid"?" on":"")} onClick={()=>setView("grid")}>⊞</button>
              <button className={"vbtn"+(view==="list"?" on":"")} onClick={()=>setView("list")}>☰</button>
            </div>
          </div>
        </div>

        {/* CATEGORY CHIPS */}
        <div className="cats">
          {CATEGORIES.map(c=>(
            <button key={c} className={"cat"+(cat===c?" on":"")} onClick={()=>setCat(c)}>
              {CAT_ICONS[c]} {c}
              <span className="cat-cnt">{catCnt(c)}</span>
            </button>
          ))}
        </div>

        {/* INFO */}
        <div className="info-row">
          <span className="info-txt">
            Showing <strong>{filtered.length}</strong> of <strong>{pets.length}</strong> pets
            {search&&<> for "<strong>{search}</strong>"</>}
          </span>
          {(search||cat!=="All")&&(
            <button className="clear-btn" onClick={()=>{setSearch("");setCat("All");}}>Clear ✕</button>
          )}
        </div>

        {/* GRID */}
        <div className={"grid"+(view==="list"?" lv":"")}>
          {loading
            ? Array(8).fill(0).map((_,i)=>(
                <div className="skel" key={i}>
                  <div className="skel-img"/>
                  <div className="skel-body">
                    <div className="skel-line"/>
                    <div className="skel-line w70"/>
                    <div className="skel-line w50"/>
                  </div>
                </div>
              ))
            : filtered.length===0
            ? <div className="empty"><span className="empty-icon">🐾</span><h3>No pets found</h3><p>Try adjusting filters</p></div>
            : filtered.map((pet,i)=>(
              <div
                key={pet.id}
                className={"card"+(view==="list"?" lv":"")}
                style={{animationDelay:(i%12)*0.05+"s"}}
                onClick={()=>setModal(pet)}
              >
                <div className="img-wrap">
                  <img src={pet.img} alt={pet.pname} className="card-img" onError={e=>{e.target.onerror=null;e.target.src=FALLBACK_IMGS[i%FALLBACK_IMGS.length];}}/>
                  {pet.badge&&<span className={"badge "+pet.badge.cls}>{pet.badge.label}</span>}
                  <button className={"wish"+(wl.includes(pet.id)?" on":"")} onClick={e=>toggleWl(pet.id,e)}>
                    {wl.includes(pet.id)?"❤️":"🤍"}
                  </button>
                  <button className="qv" onClick={e=>{e.stopPropagation();setModal(pet);}}>Quick View →</button>
                </div>
                <div className="body">
                  <div className="cat-tag">{pet.cat}</div>
                  <div className="pname">{pet.pname}</div>
                  <div className="age">🐣 {pet.age} old</div>
                  <div className="desc">{pet.desc}</div>
                  <div className="rat">
                    <span className="stars">{starsStr(pet.rating)}</span>
                    <span className="revs">({pet.reviews})</span>
                  </div>
                  <div className="price-row">
                    <div className="price"><sup>₹</sup>{pet.price.toLocaleString("en-IN")}</div>
                    <div className="btns">
                      <button className={"cart-btn"+(added[pet.id]?" ok":"")} onClick={e=>addCart(pet,e)}>
                        {added[pet.id]?"✓ Added":"🛒 Add"}
                      </button>
                      <button className="wa-btn" title="WhatsApp" onClick={e=>waInquiry(pet,e)}>💬</button>
                    </div>
                  </div>
                </div>
              </div>
            ))
          }
        </div>

        {/* MODAL */}
        {modal&&(
          <div className="modal-bg" onClick={()=>setModal(null)}>
            <div className="modal" onClick={e=>e.stopPropagation()}>
              <img src={modal.img} alt={modal.pname} className="modal-img" onError={e=>{e.target.onerror=null;e.target.src=FALLBACK_IMGS[0];}}/>
              <button className="modal-close" onClick={()=>setModal(null)}>✕</button>
              <div className="modal-body">
                <div className="cat-tag" style={{marginBottom:8}}>{modal.cat}</div>
                <div className="modal-name">{modal.pname}</div>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
                  <div className="rat" style={{margin:0}}>
                    <span className="stars">{starsStr(modal.rating)}</span>
                    <span className="revs">({modal.reviews} reviews)</span>
                  </div>
                  {modal.badge&&<span className={"badge "+modal.badge.cls} style={{position:"static"}}>{modal.badge.label}</span>}
                </div>
                <div className="modal-price">₹{modal.price.toLocaleString("en-IN")}</div>
                <p style={{fontSize:".875rem",color:"var(--muted)",lineHeight:1.75,marginBottom:20}}>
                  {modal.desc} Comes with health certificate, vaccination record & a 7-day health guarantee.
                </p>
                <div className="modal-feats">
                  {[
                    {label:"Health Status",val:"✅ Vaccinated & Certified"},
                    {label:"Delivery",val:"🚚 Free Pan India"},
                    {label:"Age",val:"🐣 "+modal.age+" old"},
                    {label:"Guarantee",val:"🛡️ 7-day Health Cover"},
                  ].map((f,i)=>(
                    <div className="feat" key={i}><strong>{f.label}</strong>{f.val}</div>
                  ))}
                </div>
                <div className="modal-acts">
                  <button className="modal-cart" onClick={()=>{addCart(modal);setModal(null);}}>
                    🛒 Add to Cart — ₹{modal.price.toLocaleString("en-IN")}
                  </button>
                  <button className="modal-wa" onClick={e=>waInquiry(modal,e)}>💬 WhatsApp</button>
                  <button className="modal-wl" onClick={e=>toggleWl(modal.id,e)}>
                    {wl.includes(modal.id)?"❤️":"🤍"}
                  </button>
                </div>
                <button className="buy-now" onClick={()=>{setModal(null);buyNow(modal);}}>⚡ Buy Now</button>
              </div>
            </div>
          </div>
        )}

        {/* TOAST */}
        <div className={"toast"+(toast.on?" on":"")}>{toast.msg}</div>
      </div>
    </>
  );
}
